<script setup lang="ts">
import { onMounted, ref } from 'vue'
import { adminAPI } from '@/api/admin'
const loading=ref(false), keyword=ref(''), status=ref(''), page=ref(1), total=ref(0); const pageSize=20; const items=ref<any[]>([])
async function load(){ loading.value=true; try{ const res=await adminAPI.getDiscordOrders({page:page.value,page_size:pageSize,keyword:keyword.value,status:status.value}); items.value=res.data?.data||[]; total.value=res.data?.pagination?.total||0 } finally{loading.value=false} }
onMounted(load)
</script>
<template><div class="space-y-4"><div><h1 class="text-2xl font-semibold">Discord 订单中心</h1><p class="text-sm text-slate-500">查看 Discord 用户创建的待支付、已支付和已完成订单。</p></div><div class="flex flex-wrap gap-2 rounded-xl border bg-white p-4"><input v-model="keyword" class="rounded border px-3 py-2" placeholder="订单号/邮箱/Discord" @keyup.enter="page=1;load()"/><select v-model="status" class="rounded border px-3 py-2" @change="page=1;load()"><option value="">全部状态</option><option value="pending_payment">待支付</option><option value="paid">已支付</option><option value="fulfilling">发货中</option><option value="delivered">已发货</option><option value="completed">已完成</option></select><button class="rounded bg-slate-900 px-4 py-2 text-white" @click="page=1;load()">查询</button></div><div class="overflow-x-auto rounded-xl border bg-white"><table class="min-w-full text-sm"><thead class="bg-slate-50 text-left"><tr><th class="p-3">订单</th><th class="p-3">用户</th><th class="p-3">金额</th><th class="p-3">支付</th><th class="p-3">时间</th></tr></thead><tbody><tr v-for="row in items" :key="row.order_id" class="border-t"><td class="p-3"><div class="font-medium">{{ row.order_no }}</div><div class="text-xs text-slate-500">{{ row.status }}</div></td><td class="p-3"><div>{{ row.discord_username }}</div><div class="text-xs text-slate-500">{{ row.email }}</div></td><td class="p-3">{{ row.total_amount }} {{ row.currency }}</td><td class="p-3"><div>{{ row.payment_status || '-' }}</div><div class="text-xs text-slate-500">{{ row.channel_type }}</div></td><td class="p-3 text-xs">{{ row.created_at }}</td></tr><tr v-if="!loading && !items.length"><td colspan="5" class="p-6 text-center text-slate-500">暂无数据</td></tr></tbody></table></div><div class="flex items-center justify-between text-sm"><span>共 {{ total }} 条</span><div class="space-x-2"><button class="rounded border px-3 py-1" :disabled="page<=1" @click="page--;load()">上一页</button><span>{{ page }}</span><button class="rounded border px-3 py-1" :disabled="items.length < pageSize" @click="page++;load()">下一页</button></div></div></div></template>
